test "error_handling_invalid_syntax" {
    // Parsing invalid syntax should produce a tree with error nodes.
    _ = try tree_sitter_language_pack.process("function function function @@@ %%%", "{\"language\":\"javascript\"}");
}

test "error_handling_unknown_language" {
    // Loading a nonexistent language should produce an error.
    const result = tree_sitter_language_pack.process("", "{\"language\":\"nonexistent_xyz\"}") catch {
        try testing.expect(true); // Error occurred as expected
        return;
    };
    _ = result;
}

test "error_process_empty_source" {
    // Process empty source code succeeds with zero metrics
    const result = try tree_sitter_language_pack.process("", "{\"language\":\"python\"}");
    try testing.expectEqual(0, result.metrics.total_lines);
}

test "parse_empty_language" {
    // process() returns error with empty language name
    const result = tree_sitter_language_pack.process("x = 1", "{\"language\":\"\"}") catch {
        try testing.expect(true); // Error occurred as expected
        return;
    };
    _ = result;
}

test "process_unknown_language" {
    // process() returns error when config language is unknown
    const result = tree_sitter_language_pack.process("x = 1", "{\"language\":\"nonexistent_xyz\"}") catch {
        try testing.expect(true); // Error occurred as expected
        return;
    };
    _ = result;
}
